CREATE OR REPLACE FUNCTION public.forward_notification_to_push() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $function$ BEGIN PERFORM net.http_post( url := 'https://zyiddcizvemzlxbydytp.supabase.co/functions/v1/send-push', headers := jsonb_build_object('Content-Type', 'application/json'), body := jsonb_build_object('type', 'INSERT', 'table', 'notifications', 'schema', 'public', 'record', to_jsonb(NEW)) ); RETURN NEW; END; $function$;